import { v4 as uuid } from 'uuid';
import { ActionHandlerTypes } from './action_handler_types';
import { ActionTypes } from './action_types';
import { PromobotLoggerConnection } from './connection';
import { EventInitiatorTypes } from './event_initiator_types';
import { EventTypes } from './event_types';
/**
 * @ignore
 */
const ObjectTypes = {
    INTERACTION_SESSION: 'INTERACTION_SESSION',
    CASE_SESSION: 'CASE_SESSION',
    EVENT: 'EVENT',
    ACTION: 'ACTION',
    STATE: 'STATE',
};
/**
 * @ignore
 */
const OperationTypes = {
    CREATE: 'CREATE',
    UPDATE: 'UPDATE',
};
/**
 * @class
 * @ignore
 */
class PromobotLogger {
    constructor() {
        /**
         * @private
         */
        this.debug = false;
        /**
         * @private
         */
        this.connections = [];
        /**
         * @private
         */
        this.subscribers = [];
        /**
         * @private
         */
        this.robotUuid = '';
        /**
         * @private
         */
        this.ownerUuid = '';
        /**
         * @private
         */
        this.robotAppId = '';
        /**
         * @private
         */
        this.robotAppLang = '';
        /**
         * @private
         */
        this.robotAppVer = '';
        /**
         * @private
         */
        this.interactionSessionId = '';
        /**
         * @private
         */
        this.caseSessionId = '';
        /**
         * @private
         */
        this.events = [];
        /**
         * @private
         */
        this.actions = [];
    }
    static getInstance() {
        if (!PromobotLogger.instance) {
            PromobotLogger.instance = new PromobotLogger();
        }
        return PromobotLogger.instance;
    }
    reset() {
        this.events = [];
        this.actions = [];
    }
    setDebug(status) {
        this.debug = status;
    }
    addConnection(options) {
        this.connections.push(new PromobotLoggerConnection(options));
    }
    subscribe(callback) {
        this.subscribers.push(callback);
    }
    uuid() {
        return uuid();
    }
    // tslint:disable-next-line: no-shadowed-variable
    setRobotUuid(uuid) {
        this.robotUuid = uuid;
    }
    // tslint:disable-next-line: no-shadowed-variable
    setOwnerUuid(uuid) {
        this.ownerUuid = uuid;
    }
    setRobotAppId(id) {
        this.robotAppId = id;
    }
    setRobotAppLang(lang) {
        this.robotAppLang = lang;
    }
    setRobotAppVer(ver) {
        this.robotAppVer = ver;
    }
    interactionSessionActive() {
        return this.interactionSessionId !== null;
    }
    getInteractionSessionId() {
        return this.interactionSessionId;
    }
    createInteractionSession() {
        this.interactionSessionId = this.uuid();
        // INTERACTION_SESSION
        this.log({
            object: ObjectTypes.INTERACTION_SESSION,
            action: OperationTypes.CREATE,
        }, {
            uuid: this.interactionSessionId,
            robotAppId: this.robotAppId,
            robotAppLang: this.robotAppLang,
            robotAppVer: this.robotAppVer,
            robotUuid: this.robotUuid,
            startDate: new Date().toUTCString(),
        });
    }
    updateInteractionSession(data = {}) {
        if (this.interactionSessionActive()) {
            this.log({
                object: ObjectTypes.INTERACTION_SESSION,
                action: OperationTypes.UPDATE,
            }, {
                uuid: this.interactionSessionId,
                data,
            });
        }
    }
    stopInteractionSession() {
        if (this.interactionSessionActive()) {
            this.log({
                object: ObjectTypes.INTERACTION_SESSION,
                action: OperationTypes.UPDATE,
            }, {
                uuid: this.interactionSessionId,
                stopDate: new Date().toUTCString(),
            });
        }
        this.interactionSessionId = '';
    }
    caseSessionActive() {
        return this.caseSessionId !== '';
    }
    getCaseSessionId() {
        return this.caseSessionId;
    }
    createCaseSession(data = {}) {
        this.reset();
        this.caseSessionId = this.uuid();
        // CASE_SESSION
        this.log({
            object: ObjectTypes.CASE_SESSION,
            action: OperationTypes.CREATE,
        }, {
            uuid: this.caseSessionId,
            robotAppId: this.robotAppId,
            robotAppLang: this.robotAppLang,
            robotAppVer: this.robotAppVer,
            robotUuid: this.robotUuid,
            startDate: new Date().toUTCString(),
            data,
        });
    }
    updateCaseSession(data = {}) {
        if (this.caseSessionActive()) {
            this.log({
                object: ObjectTypes.CASE_SESSION,
                action: OperationTypes.UPDATE,
            }, {
                uuid: this.caseSessionId,
                data,
            });
        }
    }
    stopCaseSession() {
        if (this.caseSessionActive()) {
            this.log({
                object: ObjectTypes.CASE_SESSION,
                action: OperationTypes.UPDATE,
            }, {
                uuid: this.caseSessionId,
                stopDate: new Date().toUTCString(),
            });
        }
        this.caseSessionId = '';
    }
    findParentEvent(eventId) {
        const e = this.events.find((event) => {
            return event.uuid === eventId;
        });
        if (e) {
            if (e.parentUuid) {
                return this.findParentEvent(e.parentUuid);
            }
            else {
                return e;
            }
        }
        else {
            return null;
        }
    }
    logState(eventId, state) {
        // find transition
        const parentEvent = this.findParentEvent(eventId);
        let transition = 'any';
        if (parentEvent) {
            if (parentEvent.data && parentEvent.data.transition) {
                transition = parentEvent.data.transition;
            }
        }
        // log state
        this.log({
            object: ObjectTypes.STATE,
            action: OperationTypes.CREATE,
        }, {
            uuid: this.uuid(),
            interactionSessionUuid: this.interactionSessionId,
            caseSessionUuid: this.caseSessionId,
            name: state.stateName,
            transition,
            state,
        });
    }
    logEvent(initiatorType, eventType, data = null, parentId = null) {
        const eventId = this.uuid();
        const eventData = {
            uuid: eventId,
            parentUuid: parentId,
            caseSessionUuid: this.caseSessionId,
            interactionSessionUuid: this.interactionSessionId,
            initiator: initiatorType,
            type: eventType,
            data,
        };
        this.events.push(eventData);
        // event
        this.log({
            object: ObjectTypes.EVENT,
            action: OperationTypes.CREATE,
        }, eventData);
        return eventId;
    }
    logAction(eventId, handler, type, data = null) {
        const actionId = this.uuid();
        const actionData = {
            uuid: actionId,
            eventUuid: eventId,
            handler,
            type,
            data,
        };
        this.actions.push(actionData);
        // action
        this.log({
            object: ObjectTypes.ACTION,
            action: OperationTypes.CREATE,
        }, actionData);
        return actionId;
    }
    log(meta, data) {
        if (this.debug) {
            // console.debug('send ' + meta.object, data);
        }
        if (this.robotUuid !== null &&
            this.robotAppId !== null &&
            this.robotAppLang !== null) {
            Object.assign(meta, {
                robotAppId: this.robotAppId,
                robotAppLang: this.robotAppLang,
                robotAppVer: this.robotAppVer,
                ownerUuid: this.ownerUuid,
                robotUuid: this.robotUuid,
            });
            this.subscribers.forEach((callback) => {
                if (typeof callback === 'function') {
                    // eslint-disable-next-line
                    callback({ meta, data });
                }
            });
            this.connections.forEach((connection) => connection.send({
                meta,
                data,
            }));
        }
    }
    getApiMessageFilter() {
        return {
            handle: (message) => {
                switch (message.type) {
                    case 'record.audio.request':
                        if (typeof message.start !== 'undefined') {
                            this.logAction(ActionHandlerTypes.ROBOT, ActionTypes.AUDIO_RECORD_START, message.data);
                        }
                        break;
                    case 'record.audio.response':
                        this.logEvent(EventInitiatorTypes.ROBOT, EventTypes.AUDIO_SERVICE_RESPONSE, message.data);
                        break;
                }
                /* tslint:disable */
                console.log('filter', message);
                return message;
            },
        };
    }
}
export { PromobotLogger, ActionHandlerTypes, ActionTypes, EventTypes, EventInitiatorTypes, };
