import Service from './service'
export var ApiRfidMessageType;
(function (ApiRfidMessageType) {
  ApiRfidMessageType["READER_RFID_REQUEST"] = "reader.rfid.request"
  ApiRfidMessageType["READER_RFID_RESPONSE"] = "reader.rfid.response"
})(ApiRfidMessageType || (ApiRfidMessageType = {}))
export var RfidMessageType;
(function (RfidMessageType) {
  RfidMessageType["RFID_STATUS"] = "RFID_STATUS"
  RfidMessageType["RFID_CONNECTED"] = "RFID_CONNECTED"
  RfidMessageType["RFID_ERROR"] = "RFID_ERROR"
  RfidMessageType["RFID_RESULT"] = "RFID_RESULT"
})(RfidMessageType || (RfidMessageType = {}))
/**
 * Сервис для работы со считывателем rfid-кодов
 * @version 0.0.1
 * @since 2.0.0
 */
export default class RfidService extends Service {
  constructor(messageChannel) {
    super(messageChannel)
    const messageHandler = (message) => {
      switch (message.type) {
        case ApiRfidMessageType.READER_RFID_RESPONSE:
          delete message.id
          delete message.type
          this.broadcast(RfidMessageType.RFID_STATUS, message)
          if (typeof message.result !== 'undefined') {
            this.broadcast(RfidMessageType.RFID_RESULT, message.result)
          }
          else if (typeof message.error !== 'undefined') {
            this.broadcast(RfidMessageType.RFID_ERROR, message.error)
          }
          else if (typeof message.connected !== 'undefined') {
            this.broadcast(RfidMessageType.RFID_CONNECTED, message.connected)
          }
          break
      }
    }
    this.messageChannel.subscribe(ApiRfidMessageType.READER_RFID_RESPONSE, messageHandler)
  }
  /**
     * Запросить статус подключения считывателя rfid-кодов
     *
     * @since 2.0.0
     * @return {*}  {void}
     * @memberof RfidService
     *
     * @example <caption>запросить статус подключения считывателя rfid-кодов</caption>
     * robot.barcodeService.getStatus()
     */
  getStatus() {
    return this.messageChannel.send({
      type: ApiRfidMessageType.READER_RFID_REQUEST,
      connected: '',
    })
  }
  /**
     * Сервис rfid-кодов ответил
     *
     * @since 2.0.0
     * @param {(message: Message) => void} callback
     * @return {*}  {UnsubscribeFunction}
     * @memberof RfidService
     *
     * @example <caption>cервис rfid-кодов ответил</caption>
     * robot.barcodeService.onStatus((message) => {
     *   ...
     * })
     */
  onStatus(callback) {
    return this.subscribe(RfidMessageType.RFID_STATUS, callback)
  }
  /**
     * Сервис rfid-кодов прислал сведения о подключении
     *
     * @since 2.0.0
     * @param {(connected: boolean) => void} callback
     * @return {*}  {UnsubscribeFunction}
     * @memberof RfidService
     *
     * @example <caption>cервис rfid-кодов прислал сведения о подключении</caption>
     * robot.barcodeService.onConnected((connected) => {
     *   ...
     * })
     */
  onConnected(callback) {
    return this.subscribe(RfidMessageType.RFID_CONNECTED, callback)
  }
  /**
     * Сервис rfid-кодов прислал ошибку
     *
     * @since 2.0.0
     * @param {(error: string) => void} callback
     * @return {*}  {UnsubscribeFunction}
     * @memberof RfidService
     *
     * @example <caption>cервис rfid-кодов прислал ошибку</caption>
     * robot.barcodeService.onError((error) => {
     *   ...
     * })
     */
  onError(callback) {
    return this.subscribe(RfidMessageType.RFID_ERROR, callback)
  }
  /**
     * Сервис rfid-кодов прислал результат считывания
     *
     * @since 2.0.0
     * @param {(result: string) => void} callback
     * @return {*}  {UnsubscribeFunction}
     * @memberof RfidService
     *
     * @example <caption>cервис rfid-кодов прислал результат считывания</caption>
     * robot.barcodeService.onResult(() => {
     *   ...
     * })
     */
  onResult(callback) {
    return this.subscribe(RfidMessageType.RFID_RESULT, callback)
  }
}
